#!/usr/bin/env bash
set -euo pipefail

usage() {
  cat <<'EOF'
usage: tools/esp32s3_flash_restore.sh <backup.bin> [options]

Restore an ESP32-S3 flash image over the built-in USB JTAG/serial link.

Options:
  --manifest <file>       Optional manifest file generated by the backup script.
  --port <device>         Serial port. Default: /dev/ttyACM0
  --chip <name>           esptool chip name. Default: esp32s3
  --flash-offset <addr>   Flash offset. Default: 0x0
  --baud <baud>           Serial baud rate. Default: 2000000
  --before <mode>         esptool reset mode before access. Default: default-reset
  --after <mode>          esptool reset mode after access. Default: hard-reset
  --verbose               Print the esptool command line before running it.
  -h, --help              Show this help text.

Environment:
  ESPTOOL_BIN             Explicit esptool executable to use.

Notes:
  - This writes the image verbatim starting at the selected flash offset.
  - Full-chip backups should normally be restored at offset 0x0.
EOF
}

resolve_esptool_bin() {
  if [ -n "${ESPTOOL_BIN:-}" ]; then
    printf '%s\n' "${ESPTOOL_BIN}"
    return 0
  fi
  if [ -x "./.venv/bin/esptool" ]; then
    printf '%s\n' "./.venv/bin/esptool"
    return 0
  fi
  if [ -x "/tmp/esptool-venv/bin/esptool" ]; then
    printf '%s\n' "/tmp/esptool-venv/bin/esptool"
    return 0
  fi
  if command -v esptool >/dev/null 2>&1; then
    command -v esptool
    return 0
  fi
  if command -v esptool.py >/dev/null 2>&1; then
    command -v esptool.py
    return 0
  fi
  return 1
}

PORT=${PORT:-/dev/ttyACM0}
CHIP=${CHIP:-esp32s3}
FLASH_OFFSET=${FLASH_OFFSET:-0x0}
BAUD=${BAUD:-2000000}
BEFORE_MODE=${BEFORE_MODE:-default-reset}
AFTER_MODE=${AFTER_MODE:-hard-reset}
MANIFEST_FILE=""
VERBOSE=0
BACKUP_FILE=""

while [ $# -gt 0 ]; do
  case "$1" in
    --manifest)
      shift
      MANIFEST_FILE=${1:-}
      ;;
    --port)
      shift
      PORT=${1:-}
      ;;
    --chip)
      shift
      CHIP=${1:-}
      ;;
    --flash-offset)
      shift
      FLASH_OFFSET=${1:-}
      ;;
    --baud)
      shift
      BAUD=${1:-}
      ;;
    --before)
      shift
      BEFORE_MODE=${1:-}
      ;;
    --after)
      shift
      AFTER_MODE=${1:-}
      ;;
    --verbose)
      VERBOSE=1
      ;;
    -h|--help)
      usage
      exit 0
      ;;
    -*)
      echo "Unknown option: $1" >&2
      usage >&2
      exit 2
      ;;
    *)
      if [ -n "${BACKUP_FILE}" ]; then
        echo "Unexpected positional argument: $1" >&2
        usage >&2
        exit 2
      fi
      BACKUP_FILE=$1
      ;;
  esac
  shift
done

if [ -z "${BACKUP_FILE}" ]; then
  usage >&2
  exit 2
fi

if [ ! -f "${BACKUP_FILE}" ]; then
  echo "Backup image not found: ${BACKUP_FILE}" >&2
  exit 2
fi

if [ -z "${PORT}" ]; then
  echo "Serial port must not be empty." >&2
  exit 2
fi

if ! ESPTOOL=$(resolve_esptool_bin); then
  echo "No esptool executable found. Set ESPTOOL_BIN or install upstream esptool." >&2
  exit 2
fi

if [ -z "${MANIFEST_FILE}" ]; then
  CANDIDATE_MANIFEST="${BACKUP_FILE%.bin}.manifest"
  if [ -f "${CANDIDATE_MANIFEST}" ]; then
    MANIFEST_FILE="${CANDIDATE_MANIFEST}"
  fi
fi

EXPECTED_SHA=""
EXPECTED_SIZE=""
if [ -n "${MANIFEST_FILE}" ]; then
  if [ ! -f "${MANIFEST_FILE}" ]; then
    echo "Manifest file not found: ${MANIFEST_FILE}" >&2
    exit 2
  fi
  EXPECTED_SHA=$(grep '^sha256=' "${MANIFEST_FILE}" | head -n 1 | cut -d= -f2- || true)
  EXPECTED_SIZE=$(grep '^size_bytes=' "${MANIFEST_FILE}" | head -n 1 | cut -d= -f2- || true)
fi

if [ -n "${EXPECTED_SHA}" ]; then
  ACTUAL_SHA=$(sha256sum "${BACKUP_FILE}" | awk '{print $1}')
  if [ "${ACTUAL_SHA}" != "${EXPECTED_SHA}" ]; then
    echo "SHA-256 mismatch for ${BACKUP_FILE}: expected ${EXPECTED_SHA}, got ${ACTUAL_SHA}." >&2
    exit 3
  fi
fi

if [ -n "${EXPECTED_SIZE}" ]; then
  ACTUAL_SIZE=$(stat -c%s "${BACKUP_FILE}")
  if [ "${ACTUAL_SIZE}" != "${EXPECTED_SIZE}" ]; then
    echo "Backup size mismatch for ${BACKUP_FILE}: expected ${EXPECTED_SIZE}, got ${ACTUAL_SIZE}." >&2
    exit 3
  fi
fi

TIMESTAMP_UTC=$(date -u +"%Y-%m-%dT%H:%M:%SZ")
RESTORE_DIR=$(dirname "${BACKUP_FILE}")
LOG_FILE="${RESTORE_DIR}/esp32s3-restore-${TIMESTAMP_UTC}.log"

COMMON_ARGS=(
  --chip "${CHIP}"
  --port "${PORT}"
  --baud "${BAUD}"
  --before "${BEFORE_MODE}"
  --after "${AFTER_MODE}"
)

WRITE_ARGS=(
  write-flash
  --flash-mode keep
  --flash-freq keep
  --flash-size keep
  "${FLASH_OFFSET}"
  "${BACKUP_FILE}"
)

{
  echo "[${TIMESTAMP_UTC}] esp32s3_flash_restore.sh starting"
  echo "[${TIMESTAMP_UTC}] ESPTOOL=${ESPTOOL}"
  echo "[${TIMESTAMP_UTC}] BACKUP_FILE=${BACKUP_FILE}"
  echo "[${TIMESTAMP_UTC}] MANIFEST_FILE=${MANIFEST_FILE:-<none>}"
  echo "[${TIMESTAMP_UTC}] PORT=${PORT}"
  echo "[${TIMESTAMP_UTC}] CHIP=${CHIP}"
  echo "[${TIMESTAMP_UTC}] FLASH_OFFSET=${FLASH_OFFSET}"
  echo "[${TIMESTAMP_UTC}] BAUD=${BAUD}"
  echo "[${TIMESTAMP_UTC}] BEFORE_MODE=${BEFORE_MODE}"
  echo "[${TIMESTAMP_UTC}] AFTER_MODE=${AFTER_MODE}"
} | tee "${LOG_FILE}"

if [ "${VERBOSE}" -eq 1 ]; then
  printf '[%s] esptool command:' "${TIMESTAMP_UTC}" | tee -a "${LOG_FILE}"
  printf ' %q' "${ESPTOOL}" "${COMMON_ARGS[@]}" "${WRITE_ARGS[@]}" | tee -a "${LOG_FILE}"
  printf '\n' | tee -a "${LOG_FILE}"
fi

if ! "${ESPTOOL}" "${COMMON_ARGS[@]}" "${WRITE_ARGS[@]}" 2>&1 | tee -a "${LOG_FILE}"; then
  echo "esptool failed while restoring the ESP32-S3 flash. Check ${LOG_FILE}." >&2
  exit 1
fi

echo "Restore complete:"
echo "  image: ${BACKUP_FILE}"
echo "  log: ${LOG_FILE}"
